export interface MarketStorage {
  owner: c.Address;
  conditionRegistry: c.Address;
  collateralToken: c.Address;
  jettonWallet: c.Address;
  funding: bigint;
  fee: bigint;
  stage: number;
  atomicOutcomeSlotCount?: number;
}

/**
 * Serialize MarketStorage into the contract's expected cell layout.
 *
 * Layout matches the Tolk struct:
 *   MarketStorage {
 *     owner: address
 *     atomicOutcomeSlotCount: uint32
 *     funding: uint128
 *     fee: uint64
 *     stage: uint8
 *     config: Cell<MarketConfig>
 *     state: Cell<MarketState>
 *   }
 *
 * MarketConfig (stored as ref):
 *   conditionRegistry: address
 *   collateralToken: address
 *   jettonWallet: address
 *   conditionIds: cell
 *   outcomeSlotCounts: cell
 *
 * MarketState (stored as ref):
 *   positionBalances: map<uint32, uint128>
 *   positionIds: map<uint32, uint256>
 *   accumulatedFees: uint128
 */
export function marketStorageToCell(storage: MarketStorage): c.Cell {
  // Build MarketConfig cell (as a ref)
  const configCell = beginCell()
    .storeAddress(storage.conditionRegistry)
    .storeAddress(storage.collateralToken)
    .storeAddress(storage.jettonWallet)
    .storeRef(beginCell().endCell()) // conditionIds (empty)
    .storeRef(beginCell().endCell()) // outcomeSlotCounts (empty)
    .endCell();

  // Build MarketState cell (as a ref)
  const stateCell = beginCell()
    .storeDict(null) // positionBalances
    .storeDict(null) // positionIds
    .storeUint(0, 128) // accumulatedFees
    .endCell();

  // Build root cell
  return beginCell()
    .storeAddress(storage.owner)
    .storeUint(storage.atomicOutcomeSlotCount ?? 0, 32)
    .storeUint(storage.funding, 128)
    .storeUint(storage.fee, 64)
    .storeUint(storage.stage, 8)
    .storeRef(configCell)
    .storeRef(stateCell)
    .endCell();
}

// ————————————————————————————————————————————
//   Message builders
//

export function buildPause(queryId?: bigint): c.Cell {
  return beginCell()
    .storeUint(MarketOpCodes.PAUSE, 32)
    .storeUint(queryId ?? 0n, 64)
    .endCell();
}

export function buildResume(queryId?: bigint): c.Cell {
  return beginCell()
    .storeUint(MarketOpCodes.RESUME, 32)
    .storeUint(queryId ?? 0n, 64)
    .endCell();
}

export function buildClose(queryId?: bigint): c.Cell {
  return beginCell()
    .storeUint(MarketOpCodes.CLOSE, 32)
    .storeUint(queryId ?? 0n, 64)
    .endCell();
}

export function buildChangeFee(params: {
  queryId?: bigint;
  newFee: bigint;
}): c.Cell {
  return beginCell()
    .storeUint(MarketOpCodes.CHANGE_FEE, 32)
    .storeUint(params.queryId ?? 0n, 64)
    .storeUint(params.newFee, 64)
    .endCell();
}

export function buildChangeFunding(params: {
  queryId?: bigint;
  fundingChange: bigint;
}): c.Cell {
  return beginCell()
    .storeUint(MarketOpCodes.CHANGE_FUNDING, 32)
    .storeUint(params.queryId ?? 0n, 64)
    .storeInt(params.fundingChange, 128)
    .endCell();
}

export function buildWithdrawFees(queryId?: bigint): c.Cell {
  return beginCell()
    .storeUint(MarketOpCodes.WITHDRAW_FEES, 32)
    .storeUint(queryId ?? 0n, 64)
    .endCell();
}

export function buildSellTrade(params: {
  queryId?: bigint;
  outcomeTokenAmounts: bigint[];
  minCollateralReturn: bigint;
}): c.Cell {
  const amountsCell = beginCell();
  for (const a of params.outcomeTokenAmounts) {
    amountsCell.storeInt(a, 64);
  }

  return beginCell()
    .storeUint(MarketOpCodes.SELL_TRADE, 32)
    .storeUint(params.queryId ?? 0n, 64)
    .storeRef(amountsCell.endCell())
    .storeCoins(params.minCollateralReturn)
    .endCell();
}

export function buildTradePayload(params: {
  outcomeTokenAmounts: bigint[];
  collateralLimit: bigint;
}): c.Cell {
  const amountsCell = beginCell();
  for (const a of params.outcomeTokenAmounts) {
    amountsCell.storeInt(a, 64);
  }

  return beginCell()
    .storeUint(MarketOpCodes.TRADE, 32)
    .storeRef(amountsCell.endCell())
    .storeInt(params.collateralLimit, 128)
    .endCell();
}

